package scanner

import (
	"context"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/navidrome/navidrome/conf"
	"github.com/navidrome/navidrome/db"
	"github.com/navidrome/navidrome/log"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/model/repo"
	"github.com/navidrome/navidrome/tests"
)

// TestScannerIntegration_FullScan tests a complete scan of a music library with metadata extraction
func TestScannerIntegration_FullScan(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)

	ctx := context.Background()
	ds := repo.NewDataStore(db.Db())
	testDir := setupTestMusicLibrary(t)
	defer os.RemoveAll(testDir)

	// Create library
	lib := &model.Library{
		Name: "Test Library",
		Path: testDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// Create scanner and perform scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// Verify that changes were detected
	if changeCount == 0 {
		t.Error("Expected changes to be detected, but got 0")
	}

	// Verify media files were created in the database
	mediaFileRepo := ds.MediaFile(ctx)
	files, err := mediaFileRepo.FindAllByPath(testDir)
	if err != nil {
		t.Fatalf("Failed to query media files: %v", err)
	}

	if len(files) == 0 {
		t.Error("Expected media files to be created, but found none")
	}

	// Verify metadata was extracted correctly
	if len(files) > 0 {
		mf := files[0]
		if mf.Path == "" {
			t.Error("Media file path is empty")
		}
		if mf.Title == "" && filepath.Ext(mf.Path) != "" {
			// Title should be at least the filename if metadata is missing
			t.Logf("Warning: Title is empty for file %s", mf.Path)
		}
	}
}

// TestScannerIntegration_MetadataExtraction tests that metadata is correctly extracted from audio files
func TestScannerIntegration_MetadataExtraction(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)

	ctx := context.Background()
	ds := repo.NewDataStore(db.Db())

	// Use existing test fixture
	fixtureDir := "tests/fixtures"
	if _, err := os.Stat(fixtureDir); err != nil {
		t.Skipf("Test fixtures not found at %s", fixtureDir)
	}

	lib := &model.Library{
		Name: "Fixtures Library",
		Path: fixtureDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// Scan the fixtures directory
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("Scan completed with error (may be expected for fixtures): %v", err)
	}

	if changeCount == 0 {
		t.Logf("Warning: No changes detected in fixtures directory")
	}

	// Verify that at least some metadata was extracted
	mediaFileRepo := ds.MediaFile(ctx)
	files, err := mediaFileRepo.FindAllByPath(fixtureDir)
	if err != nil {
		t.Logf("Failed to query media files: %v", err)
	}

	if len(files) > 0 {
		mf := files[0]
		t.Logf("Sample metadata extracted - Title: %s, Artist: %s, Album: %s", mf.Title, mf.Artist, mf.Album)
	}
}

// TestScannerIntegration_AlbumAndArtistCreation tests that albums and artists are created correctly
func TestScannerIntegration_AlbumAndArtistCreation(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)

	ctx := context.Background()
	ds := repo.NewDataStore(db.Db())
	testDir := setupTestMusicLibrary(t)
	defer os.RemoveAll(testDir)

	lib := &model.Library{
		Name: "Test Library",
		Path: testDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// Perform scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("Scan error (may be expected): %v", err)
	}

	// Check media files were created
	mediaFileRepo := ds.MediaFile(ctx)
	files, err := mediaFileRepo.FindAllByPath(testDir)
	if err != nil {
		t.Fatalf("Failed to query media files: %v", err)
	}

	if len(files) == 0 {
		t.Log("No media files found - skipping artist/album checks")
		return
	}

	// Collect unique artist and album IDs
	artistIDs := make(map[string]struct{})
	albumIDs := make(map[string]struct{})

	for _, mf := range files {
		if mf.ArtistID != "" {
			artistIDs[mf.ArtistID] = struct{}{}
		}
		if mf.AlbumID != "" {
			albumIDs[mf.AlbumID] = struct{}{}
		}
	}

	// Verify artists exist
	artistRepo := ds.Artist(ctx)
	for artistID := range artistIDs {
		_, err := artistRepo.Get(artistID)
		if err != nil {
			t.Logf("Warning: Artist %s not found in database: %v", artistID, err)
		}
	}

	// Verify albums exist
	albumRepo := ds.Album(ctx)
	for albumID := range albumIDs {
		_, err := albumRepo.Get(albumID)
		if err != nil {
			t.Logf("Warning: Album %s not found in database: %v", albumID, err)
		}
	}
}

// TestScannerIntegration_IncrementalScan tests that re-scanning with no changes produces no updates
func TestScannerIntegration_IncrementalScan(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)

	ctx := context.Background()
	ds := repo.NewDataStore(db.Db())
	testDir := setupTestMusicLibrary(t)
	defer os.RemoveAll(testDir)

	lib := &model.Library{
		Name: "Test Library",
		Path: testDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// First scan - full scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	firstChangeCount, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("First scan error: %v", err)
	}

	t.Logf("First scan change count: %d", firstChangeCount)

	// Update library LastScanAt
	lib2, err := libRepo.Get(lib.ID)
	if err != nil {
		t.Fatalf("Failed to fetch updated library: %v", err)
	}

	// Second scan - incremental scan (no changes)
	scanner2 := NewTagScanner(ds, nil, nil)
	progress2 := make(chan uint32, 100)
	secondChangeCount, err := scanner2.Scan(ctx, *lib2, false, progress2)
	close(progress2)

	if err != nil {
		t.Logf("Second scan error (expected): %v", err)
	}

	t.Logf("Second scan change count: %d", secondChangeCount)

	// If files were added in first scan, second scan should detect no changes
	if firstChangeCount > 0 && secondChangeCount != 0 {
		t.Logf("Warning: Second scan detected %d changes, expected 0 since no files were modified", secondChangeCount)
	}
}

// TestScannerIntegration_FileDeletionDetection tests that deleted files are removed from the database
func TestScannerIntegration_FileDeletionDetection(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)

	ctx := context.Background()
	ds := repo.NewDataStore(db.Db())
	testDir := setupTestMusicLibrary(t)
	defer os.RemoveAll(testDir)

	lib := &model.Library{
		Name: "Test Library",
		Path: testDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// First scan - initial population
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("First scan error: %v", err)
	}

	// Get initial file count
	mediaFileRepo := ds.MediaFile(ctx)
	filesBeforeDeletion, err := mediaFileRepo.FindAllByPath(testDir)
	if err != nil {
		t.Fatalf("Failed to query media files: %v", err)
	}

	initialCount := len(filesBeforeDeletion)
	t.Logf("Initial file count: %d", initialCount)

	if initialCount == 0 {
		t.Skip("No files created in initial scan, skipping deletion test")
	}

	// Delete first file from disk
	fileToDelete := filesBeforeDeletion[0].Path
	if err := os.Remove(fileToDelete); err != nil {
		t.Fatalf("Failed to delete test file: %v", err)
	}

	// Update library timestamp to force re-scan of the directory
	lib.LastScanAt = time.Now().Add(-1 * time.Hour)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to update library: %v", err)
	}

	// Second scan - should detect deletion
	scanner2 := NewTagScanner(ds, nil, nil)
	progress2 := make(chan uint32, 100)
	changeCount, err := scanner2.Scan(ctx, lib, false, progress2)
	close(progress2)

	if err != nil {
		t.Logf("Second scan error: %v", err)
	}

	if changeCount == 0 {
		t.Logf("Warning: No changes detected after file deletion")
	}

	// Verify file was deleted from database
	filesAfterDeletion, err := mediaFileRepo.FindAllByPath(testDir)
	if err != nil {
		t.Fatalf("Failed to query media files after deletion: %v", err)
	}

	finalCount := len(filesAfterDeletion)
	t.Logf("Final file count: %d (deleted %d files)", finalCount, initialCount-finalCount)

	// Check if the deleted file is no longer in the database
	found := false
	for _, f := range filesAfterDeletion {
		if f.Path == fileToDelete {
			found = true
			break
		}
	}

	if found {
		t.Error("Deleted file still exists in database after scan")
	}
}

// TestScannerIntegration_DirectoryStructure tests scanning of nested directory structures
func TestScannerIntegration_DirectoryStructure(t *testing.T) {
	tests.Init(t, true)
	conf.Server.DbPath = "file::memory:?cache=shared"
	defer db.Init()()
	log.SetLevel(log.LevelFatal)

	ctx := context.Background()
	ds := repo.NewDataStore(db.Db())

	// Create a nested directory structure
	testDir := t.TempDir()
	artistDir := filepath.Join(testDir, "TestArtist")
	albumDir := filepath.Join(artistDir, "TestAlbum")
	if err := os.MkdirAll(albumDir, 0755); err != nil {
		t.Fatalf("Failed to create test directories: %v", err)
	}

	// Copy a test file to the album directory
	srcFile := "tests/fixtures/test.mp3"
	if _, err := os.Stat(srcFile); err == nil {
		dstFile := filepath.Join(albumDir, "track1.mp3")
		content, err := os.ReadFile(srcFile)
		if err != nil {
			t.Logf("Warning: Could not copy test file: %v", err)
		} else {
			if err := os.WriteFile(dstFile, content, 0644); err != nil {
				t.Logf("Warning: Could not write test file: %v", err)
			}
		}
	}

	lib := &model.Library{
		Name: "Nested Test Library",
		Path: testDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// Scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("Scan completed with error (may be expected): %v", err)
	}

	t.Logf("Detected %d changes in nested structure", changeCount)
}

// setupTestMusicLibrary creates a temporary directory with test audio files for integration testing
func setupTestMusicLibrary(t *testing.T) string {
	testDir := t.TempDir()

	// Copy test fixtures to the test directory
	fixtureDir := "tests/fixtures"
	if _, err := os.Stat(fixtureDir); err != nil {
		t.Logf("Warning: Test fixtures directory not found at %s", fixtureDir)
		return testDir
	}

	// Copy a few audio files from fixtures
	testFiles := []string{
		"test.mp3",
		"test.m4a",
		"test.flac",
	}

	for _, filename := range testFiles {
		src := filepath.Join(fixtureDir, filename)
		if _, err := os.Stat(src); err == nil {
			dst := filepath.Join(testDir, filename)
			content, err := os.ReadFile(src)
			if err != nil {
				t.Logf("Warning: Could not read fixture file %s: %v", filename, err)
				continue
			}
			if err := os.WriteFile(dst, content, 0644); err != nil {
				t.Logf("Warning: Could not write test file %s: %v", filename, err)
			}
		}
	}

	return testDir
}

