   179→	}
   180→
   181→	err = s.ds.GC(log.NewContext(ctx), s.lib.Path)
   182→	log.Info("Finished processing Music Folder", "folder", s.lib.Path, "elapsed", time.Since(start),
   183→		"added", s.cnt.added, "updated", s.cnt.updated, "deleted", s.cnt.deleted, "playlistsImported", s.cnt.playlists)
   184→
   185→	return s.cnt.total(), err
   186→}
