   243→func (s *TagScanner) processDeletedDir(ctx context.Context, refresher *refresher, dir string) error {
   244→	start := time.Now()
   245→
   246→	mfs, err := s.ds.MediaFile(ctx).FindAllByPath(dir)
   247→	if err != nil {
