   385→		// If track from folder is newer than the one in DB, update/insert in DB
   386→		log.Trace(ctx, "Updating mediaFiles in DB", "dir", dir, "files", chunk, "numFiles", len(chunk))
   387→		for i := range newTracks {
   388→			n := newTracks[i]
