		t.Fatalf("Failed to create library: %v", err)
	}

	// First scan - initial population
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("First scan error: %v", err)
	}

	// Get initial file count
	mediaFileRepo := ds.MediaFile(ctx)
	filesBeforeDeletion, err := mediaFileRepo.FindAllByPath(testDir)
	if err != nil {
		t.Fatalf("Failed to query media files: %v", err)
	}

	initialCount := len(filesBeforeDeletion)
	t.Logf("Initial file count: %d", initialCount)

	if initialCount == 0 {
		t.Skip("No files created in initial scan, skipping deletion test")
	}

	// Delete first file from disk
	fileToDelete := filesBeforeDeletion[0].Path
	if err := os.Remove(fileToDelete); err != nil {
		t.Fatalf("Failed to delete test file: %v", err)
	}

	// Update library timestamp to force re-scan of the directory
	lib.LastScanAt = time.Now().Add(-1 * time.Hour)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to update library: %v", err)
	}

	// Second scan - should detect deletion
	scanner2 := NewTagScanner(ds, nil, nil)
	progress2 := make(chan uint32, 100)
	changeCount, err := scanner2.Scan(ctx, lib, false, progress2)
	close(progress2)

	if err != nil {
		t.Logf("Second scan error: %v", err)
	}

