	testDir := t.TempDir()
	artistDir := filepath.Join(testDir, "TestArtist")
	albumDir := filepath.Join(artistDir, "TestAlbum")
	if err := os.MkdirAll(albumDir, 0755); err != nil {
		t.Fatalf("Failed to create test directories: %v", err)
	}

	// Copy a test file to the album directory
	srcFile := "tests/fixtures/test.mp3"
	if _, err := os.Stat(srcFile); err == nil {
		dstFile := filepath.Join(albumDir, "track1.mp3")
		content, err := os.ReadFile(srcFile)
		if err != nil {
			t.Logf("Warning: Could not copy test file: %v", err)
		} else {
			if err := os.WriteFile(dstFile, content, 0644); err != nil {
				t.Logf("Warning: Could not write test file: %v", err)
			}
		}
	}

	lib := &model.Library{
		Name: "Nested Test Library",
		Path: testDir,
	}
	libRepo := ds.Library(ctx)
	if err := libRepo.Put(lib); err != nil {
		t.Fatalf("Failed to create library: %v", err)
	}

	// Scan
	scanner := NewTagScanner(ds, nil, nil)
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil {
		t.Logf("Scan completed with error (may be expected): %v", err)
	}

	t.Logf("Detected %d changes in nested structure", changeCount)
}

// setupTestMusicLibrary creates a temporary directory with test audio files for integration testing
func setupTestMusicLibrary(t *testing.T) string {
	testDir := t.TempDir()

	// Copy test fixtures to the test directory
	fixtureDir := "tests/fixtures"
	if _, err := os.Stat(fixtureDir); err != nil {
		t.Logf("Warning: Test fixtures directory not found at %s", fixtureDir)
		return testDir
	}

	// Copy a few audio files from fixtures
	testFiles := []string{
		"test.mp3",
		"test.m4a",
		"test.flac",
	}

	for _, filename := range testFiles {
		src := filepath.Join(fixtureDir, filename)
		if _, err := os.Stat(src); err == nil {
			dst := filepath.Join(testDir, filename)
			content, err := os.ReadFile(src)
			if err != nil {
				t.Logf("Warning: Could not read fixture file %s: %v", filename, err)
				continue
			}
			if err := os.WriteFile(dst, content, 0644); err != nil {
				t.Logf("Warning: Could not write test file %s: %v", filename, err)
			}
		}
	}

	return testDir
}
